#include <vector>
#include <unordered_map>
#include <set>
#include <algorithm>

using namespace std;

class UnionFind {
private:
    vector<long long> parent;
    vector<long long> min_id;
    vector<set<long long>> online_sets;

public:
    UnionFind(long long c) {
        parent.resize(c + 1);
        min_id.resize(c + 1);
        online_sets.resize(c + 1);
        for (long long i = 1; i <= c; ++i) {
            parent[i] = i;
            min_id[i] = i;
            online_sets[i].insert(i);
        }
    }

    long long find(long long x) {
        if (parent[x] != x) {
            parent[x] = find(parent[x]);
        }
        return parent[x];
    }

    void unionSets(long long x, long long y) {
        long long rootX = find(x);
        long long rootY = find(y);
        if (rootX != rootY) {
            if (online_sets[rootX].size() < online_sets[rootY].size()) {
                swap(rootX, rootY);
            }
            parent[rootY] = rootX;
            online_sets[rootX].insert(online_sets[rootY].begin(), online_sets[rootY].end());
            min_id[rootX] = min(min_id[rootX], min_id[rootY]);
        }
    }

    set<long long>& getOnlineSet(long long x) {
        return online_sets[find(x)];
    }

    long long getMinId(long long x) {
        return min_id[find(x)];
    }
};

vector<long long> solve(long long c, vector<vector<long long>> connections, vector<vector<long long>> queries) {
    UnionFind uf(c);
    for (const auto& conn : connections) {
        uf.unionSets(conn[0], conn[1]);
    }

    vector<bool> online(c + 1, true);
    vector<long long> result;

    for (const auto& query : queries) {
        long long type = query[0];
        long long x = query[1];
        if (type == 1) {
            if (online[x]) {
                result.push_back(x);
            } else {
                auto& online_set = uf.getOnlineSet(x);
                if (online_set.empty()) {
                    result.push_back(-1);
                } else {
                    result.push_back(*online_set.begin());
                }
            }
        } else if (type == 2) {
            if (online[x]) {
                online[x] = false;
                long long root = uf.find(x);
                uf.getOnlineSet(root).erase(x);
            }
        }
    }

    return result;
}

