import java.util.*;

public class Solution {
    public static long[] solve(long c, long[][] connections, long[][] queries) {
        UnionFind uf = new UnionFind(c);
        for (long[] conn : connections) {
            uf.unionSets(conn[0], conn[1]);
        }

        boolean[] online = new boolean[(int) (c + 1)];
        Arrays.fill(online, true);
        List<Long> resultList = new ArrayList<>();

        for (long[] query : queries) {
            long type = query[0];
            long x = query[1];
            if (type == 1) {
                if (online[(int) x]) {
                    resultList.add(x);
                } else {
                    TreeSet<Long> onlineSet = uf.getOnlineSet(x);
                    if (onlineSet.isEmpty()) {
                        resultList.add(-1L);
                    } else {
                        resultList.add(onlineSet.first());
                    }
                }
            } else if (type == 2) {
                if (online[(int) x]) {
                    online[(int) x] = false;
                    long root = uf.find(x);
                    uf.getOnlineSet(root).remove(x);
                }
            }
        }

        long[] result = new long[resultList.size()];
        for (int i = 0; i < result.length; i++) {
            result[i] = resultList.get(i);
        }
        return result;
    }

    static class UnionFind {
        private long[] parent;
        private long[] minId;
        private TreeSet<Long>[] onlineSets;

        public UnionFind(long c) {
            parent = new long[(int) (c + 1)];
            minId = new long[(int) (c + 1)];
            onlineSets = new TreeSet[(int) (c + 1)];
            for (long i = 1; i <= c; i++) {
                parent[(int) i] = i;
                minId[(int) i] = i;
                onlineSets[(int) i] = new TreeSet<>();
                onlineSets[(int) i].add(i);
            }
        }

        public long find(long x) {
            if (parent[(int) x] != x) {
                parent[(int) x] = find(parent[(int) x]);
            }
            return parent[(int) x];
        }

        public void unionSets(long x, long y) {
            long rootX = find(x);
            long rootY = find(y);
            if (rootX != rootY) {
                if (onlineSets[(int) rootX].size() < onlineSets[(int) rootY].size()) {
                    long temp = rootX;
                    rootX = rootY;
                    rootY = temp;
                }
                parent[(int) rootY] = rootX;
                onlineSets[(int) rootX].addAll(onlineSets[(int) rootY]);
                minId[(int) rootX] = Math.min(minId[(int) rootX], minId[(int) rootY]);
            }
        }

        public TreeSet<Long> getOnlineSet(long x) {
            return onlineSets[(int) find(x)];
        }

        public long getMinId(long x) {
            return minId[(int) find(x)];
        }
    }
}
