public class Solution {
    public static long[] solve(long c, long[][] connections, long[][] queries) {
        UnionFind uf = new UnionFind(c);
        for (long[] conn : connections) {
            uf.unionSets(conn[0], conn[1]);
        }

        boolean[] online = new boolean[(int)c + 1];
        Arrays.fill(online, true);
        List<Long> resultList = new ArrayList<>();

